INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00626', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「我給自己機會；我是一粒種籽，我也不僅是一粒——我是一棵樹；我種 我自己。」上文旨在強調：', '["播種須把握機會，錯過機會無法發芽", "珍惜時光，一棵樹無法回到種籽狀態", "單薄一粒種籽，成為大樹後機會才多", "必須播種才有機會，機會是自己給的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00627', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「不管是出現在小說、電影、漫畫還是廣告片裡，唯有故事能夠讓我們瞬 間進入『另一個人生』。人生在世，大部分的人都不會對自己的處境完全 滿意，卻也沒有辦法可以改變。如果不考慮投胎的話，『聽故事』是唯一 可以讓你暫時逃離當下人生的解決方案。這種遁逃，成就了人類最古老也 最根深柢固的娛樂形式。」依據上文，下列敘述最正確的是：', '["故事提供令人滿意的人生方案", "故事可以讓人反省自己的人生", "故事的世界中充滿著人生智慧", "故事可讓人感受不一樣的人生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00628', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「鐵鎚原是用來敲東西的，現在拿來炒菜，當然炒不好，而世人居然還要 指著鐵鎚痛罵：『要你有什麼用？』」下列敘述，最能說明此段文字主旨 的是：', '["無用之用，是為大用", "指出缺失，才能精益求精", "經過錘鍊，才能夠出類拔萃", "器物是否有用，當視其使用目的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00629', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「小學的時候，可能仰慕某一位老師或明星；長大一點，可能認定某某作 家是偶像。我們學習這些人的典範，然後二十五歲以後，是我們要開始自 己創造。如果一輩子都在學別人，我們就不可能成為一個典範；對我們來 說，只有在自己能夠成為一個典範時，過去的偶像才發揮出真正的正面作 用。」根據上文，偶像對自己的正面影響是：', '["隨時跟得上時代潮流", "使表現獲得眾人崇拜", "更懂得發揮自身特色", "有明確可遵循的目標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00630', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「對群島國來說，每一座島嶼或島礁，儘管面積不大或無人居住，但每個 撒佈在我們海域裡的島或礁，都比珍珠還要珍貴。以因果關係來說，這些 『島或礁』是因，『我們的海域』是果；以幾何概念來說，這些珍珠是點， 這些點所撐張的海域範圍是面。」根據上文，島嶼或島礁的珍貴處在於：', '["延伸的海權", "稀有的礦產", "擁有的陸地面積", "蘊藏的海洋資源"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00631', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「問題，是所有創意的起點。一般都說需求是創造之母，可是汽車大王 亨利．福特曾說：『去問消費者，你需要什麼？他們會說，我要一輛更好 的馬車，因為他們不知道會有汽車。』人不一定知道自己的需求，他如果 知道，創意就開始了。問題會引發創造的動機與動力，所以問題才是創造 之父。 世界上有兩種人，一種可以看出問題，一種看不出。前者又分兩種，想辦 法解決和只會抱怨。解決問題像爬階梯，每解決一個問題，就爬上一層階 梯。每上一個階梯會讓你看得更廣、更遠，看出新的問題。用問題的電波 向四周探索，會發現一大堆問題等著解決。不論問題大小，都需要創意去 解決，小創意也有大影響。」根據上文，下列選項最符合文意的是：', '["問題與創意不相干", "在抱怨中必有創意", "創意來自解決問題", "創意來自實際需求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00632', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '承上題，文中指出：「解決問題像爬階梯」，這句話意指：', '["發明是發明家的專利", "創意等待我們去發現", "問題如雪崩般一次湧入", "不同層次面對不同問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00633', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '下列對聯，何者最能表現出藉景物自我勉勵之意？', '["清泉稱人意，古巷烹茶香", "柳堆千疊綠，泉湧一池春", "江山開眼界，風雪煉精神", "柳浪煙竹畫，湖山藕荷詩"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00634', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '在〈卡債與旅行的意義〉這首詩中有以下的句子：「對不起我只能盡最低 應盡責任╱因為我只繳得起最低應繳金額╱美景我們都看過了╱你們也 看過了就好╱在螢幕上看也差不多╱美食可以看看就好╱只要餓了什麼 都好吃╱吃進肚子裡也差不多」下列選項，何者最符合本詩的意旨？', '["在螢幕上看美景、賞美食，也別有一番情趣", "連卡債都還不清，更遑論旅行賞美景、吃美食", "即使償還卡債很吃力，仍然要賞美景、吃美食", "每月繳交最低應繳金額，就是作者最盡責的表現"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00635', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '魯有執長竿入城門者，初豎執之，不可入；橫執之，亦不可入，計無所出。 俄有老父至曰：「吾非聖人，但見事多矣。何不以鋸中截而入？」遂依而 截之。（邯鄲淳《笑林》）此笑話之啟示在於：', '["人謀不臧，道謀是用", "毋必毋固，通權而達變", "不語海於井蛙，不語冰於夏蟲", "學而不思則罔，思而不學則殆"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
